        tasks: [
          { id: 'hw1', label: 'Draw a floor plan of one floor of your home at 1:100 scale — include all rooms, doors, windows and fixed furniture', hint: '' },
          { id: 'hw2', label: 'Draw one elevation (the front of your home) at 1:100 — include doors, windows, roof outline and material hatching', hint: '' },
        ],
